// ============================================================
// AGENT: Career Goal v1.0.0
// PURPOSE: Infer career goals, target roles, and search strategy
// DEPENDS ON: resume_intelligence output
// STATUS: PLACEHOLDER — Replace with real LLM logic in Phase 3
// ============================================================

const input = $input.first().json;
const ctx   = input.execution_context;

if (!ctx)                   throw new Error('[career_goal] Missing execution_context');
if (!ctx.results?.resume_profile) throw new Error('[career_goal] Missing resume_profile — career goal depends on resume_intelligence');

const started_at = Date.now();
console.log(`[career_goal] START | execution_id=${ctx.execution_id}`);

// ⚠️  PLACEHOLDER RESPONSE
// In Phase 3, this will call Claude Haiku with the resume_profile
// to infer career goals, search keywords, and preferences.

const resume  = ctx.results.resume_profile;
const prefs   = ctx.preferences;

// Build a placeholder career goal using user preferences as seed
const placeholder_career_goals = {
  primary_role:       prefs.target_roles?.[0]       || `${resume.seniority_level} Developer`,
  secondary_roles:    prefs.target_roles?.slice(1)  || [],
  target_industries:  prefs.target_industries       || ['Technology', 'Software'],
  experience_level:   resume.seniority_level        || 'junior',
  search_keywords:    [
    ...(resume.skills?.slice(0, 5) || []),
    ...(prefs.target_roles         || ['software engineer'])
  ],
  excluded_keywords: [],
  location_strategy: {
    preferred_locations: prefs.preferred_locations  || [],
    remote_preference:   prefs.remote_preference    || 'any',
    willing_to_relocate: false
  },
  salary_expectations: {
    min: prefs.salary_min || 0,
    currency: 'USD'
  },
  job_types:  ['full_time'],
  inferred_from: 'placeholder'
};

const duration_ms = Date.now() - started_at;
console.log(`[career_goal] COMPLETE (placeholder) | primary_role=${placeholder_career_goals.primary_role}`);

return [{
  json: {
    execution_context: ctx,
    career_goals: placeholder_career_goals,
    status: 'placeholder',
    agent_meta: {
      agent_id:      'agent-career-goal',
      agent_version: '1.0.0',
      execution_id:  ctx.execution_id,
      model_used:    null,
      tokens_total:  0,
      duration_ms,
      status:        'placeholder',
      error:         null
    }
  }
}];
